div.au-select {
  position: relative;
  background: var(--color-input-background);

  &--opened,
  &:active {
    border-color: var(--color-primary-blue-transparent);
  }
}

.au-select {
  & > svg {
    position: absolute;
    right: 16px;
    top: 50%;
    width: 12px;
    height: 8px;
    transform: translateY(-50%);
    pointer-events: none;
  }

  &__input {
    width: 100%;
    height: 100%;
    border-radius: 12px;
    color: var(--color-primary-blue);
    font-weight: 600;
    font-size: 14px;
    line-height: calc(1em * var(--line-height-ratio));
    border: none;
    outline: none;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    cursor: pointer;
  }

  &--multiple > &__input {
    font-weight: 500;
  }

  &--empty > &__input {
    font-weight: 400;
    color: var(--color-placeholder);
  }

  &__options-wrapper {
    position: absolute;
    left: 0;
    display: none;
    width: 100%;
    max-height: 238px;
    background: var(--color-input-background);
    border: 1px solid var(--color-border);
    border-radius: 12px;
    z-index: 10;
    overflow: hidden;
    margin-top: 6px;

    &::before,
    &::after {
      position: absolute;
      z-index: 100;
      height: 50px;
      pointer-events: none;
      transition-property: opacity, visibility;
      transition-duration: 300ms;
      content: '';
    }

    &::before {
      inset: 0 0 auto;
      background-image: linear-gradient(
        to bottom,
        var(--color-input-background),
        transparent
      );
    }

    &::after {
      inset: auto 0 0;
      background-image: linear-gradient(
        transparent,
        var(--color-input-background)
      );
    }

    .au-select--start &::before,
    .au-select--end &::after {
      opacity: 0;
    }
  }

  &--opened &__options-wrapper {
    display: block;
  }

  &__options-list {
    position: relative;
    max-height: 238px;
    display: flex;
    flex-direction: column;
    overflow-y: scroll;
    padding: 10px;
  }

  &__option {
    cursor: pointer;
    font-weight: 400;
    font-size: 14px;
    line-height: calc(1em * var(--line-height-ratio));
    padding: 10px 0;
    border-bottom: 1px solid var(--color-border);

    &:first-child {
      padding-top: 0;
    }

    &:last-child {
      padding-bottom: 0;
      border-bottom: none;
    }

    &--checked:hover,
    &:hover {
      color: var(--color-primary-blue-lighter);
    }

    &--checked {
      color: var(--color-primary-blue);
    }
  }
}

